mapper.select:
SELECT u.id, u.username, u.nickname, u.real_name, u.gender, u.phone, u.email, u.status, u.locked, u.last_login_time, u.create_time, u.remark, d.dept_name primaryDeptName, p.post_name primaryPostName FROM system_user u LEFT JOIN system_user_dept ud on u.id = ud.user_id AND ud.is_primary = 1 LEFT JOIN system_dept d on ud.dept_id = d.id LEFT JOIN system_user_post up on u.id = up.user_id AND up.is_primary = 1 LEFT JOIN system_post p on up.post_id = p.id
u.deleted = 0
AND u.username LIKE CONCAT('%', #{dto.username}, '%')
AND u.nickname LIKE CONCAT('%', #{dto.nickname}, '%')
AND u.real_name LIKE CONCAT('%', #{dto.realName}, '%')
AND u.email = #{dto.email}
AND u.phone = #{dto.phone}
AND u.status = #{dto.status}
AND u.locked = #{dto.locked}
AND u.gender = #{dto.gender}
AND u.create_time >= #{dto.createTimeStart}
AND u.create_time <= #{dto.createTimeEnd}
AND u.last_login_time >= #{dto.lastLoginTimeStart}
AND u.last_login_time <= #{dto.lastLoginTimeEnd}
AND EXISTS ( SELECT 1 FROM system_user_dept ud WHERE ud.user_id = u.id AND ud.dept_id = #{dto.deptId} )
AND EXISTS ( SELECT 1 FROM system_user_post up WHERE up.user_id = u.id AND up.post_id = #{dto.postId} )
AND EXISTS ( SELECT 1 FROM system_user_role ur WHERE ur.user_id = u.id AND ur.role_id = #{dto.roleId} )
AND EXISTS ( SELECT 1 FROM system_user_role ur INNER JOIN system_role r ON r.id = ur.role_id AND r.deleted = 0 WHERE ur.user_id = u.id AND r.role_code = #{dto.roleCode} )
ORDER BY u.create_time DESC
